from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""

    from collections import defaultdict

    # Helper to join multiple objects with commas and 'and'
    def join_objs(objs: list[str]) -> str:
        if not objs:
            return ""
        if len(objs) == 1:
            return objs[0]
        return ", ".join(objs[:-1]) + " and " + objs[-1]

    # Group objects by (subject, predicate)
    groups = defaultdict(list)  # type: dict[tuple[str, str], list[str]]
    for t in triples:
        groups[(t.subject, t.predicate)].append(t.object)

    # Determine the main subject (the subject of the first triple)
    main_subject = triples[0].subject

    # Collect predicates for the main subject
    main_data = {pred: objs for (sub, pred), objs in groups.items() if sub == main_subject}

    clauses = []

    # 1. Background / occupation / nationality as introductory clause
    if "background" in main_data:
        clauses.append(f"is a {main_data['background'][0].lower()}")
    elif "occupation" in main_data:
        clauses.append(f"works as {main_data['occupation'][0].lower()}")
    elif "nationality" in main_data:
        clauses.append(f"is {main_data['nationality'][0]}")

    # 2. Birth information
    if "birthDate" in main_data:
        clauses.append(f"was born on {main_data['birthDate'][0]}")
    elif "birthYear" in main_data:
        clauses.append(f"was born in {main_data['birthYear'][0]}")
    elif "birthPlace" in main_data:
        clauses.append(f"was born in {main_data['birthPlace'][0]}")

    # 3. Genre with possible stylistic origin and derivative
    if "genre" in main_data:
        genre_phrase = f"performs {main_data['genre'][0]} music"
        # stylistic origin
        if "stylisticOrigin" in main_data:
            genre_phrase += f", which has its stylistic origins in {join_objs(main_data['stylisticOrigin'])}"
        # derivative
        if "derivative" in main_data:
            genre_phrase += f", and is derived from {join_objs(main_data['derivative'])}"
        clauses.append(genre_phrase)

    # 4. Instrument
    if "instrument" in main_data:
        clauses.append(f"plays the {main_data['instrument'][0]}")

    # 5. Associated band / musical artist
    if "associatedBand/associatedMusicalArtist" in main_data:
        clauses.append(f"is associated with {join_objs(main_data['associatedBand/associatedMusicalArtist'])}")

    # 6. Record label
    if "recordLabel" in main_data:
        clauses.append(f"is signed to {main_data['recordLabel'][0]}")

    # 7. Active years
    if "activeYearsStartYear" in main_data:
        start = main_data["activeYearsStartYear"][0]
        end = main_data.get("activeYearsEndYear", [None])[0]
        if end:
            clauses.append(f"was active from {start} to {end}")
        else:
            clauses.append(f"started their career in {start}")

    # 8. Death information
    if "deathDate" in main_data:
        clauses.append(f"died on {main_data['deathDate'][0]}")
    if "deathPlace" in main_data:
        clauses.append(f"died in {main_data['deathPlace'][0]}")

    # 9. Alternative name
    if "alternativeName" in main_data:
        clauses.append(f"is also known as {main_data['alternativeName'][0]}")

    # Build the main sentence
    if clauses:
        main_sentence = f"{main_subject} " + ", ".join(clauses) + "."
        main_sentence = main_sentence[0].upper() + main_sentence[1:]
    else:
        main_sentence = f"{main_subject}."

    # Sentences for other subjects
    other_sentences = []
    for (sub, pred), objs in groups.items():
        if sub == main_subject:
            continue
        # Simple phrasing for non‑main subjects
        phrase = ""
        if pred == "birthDate":
            phrase = f"{sub} was born on {objs[0]}"
        elif pred == "birthPlace":
            phrase = f"{sub} was born in {objs[0]}"
        elif pred == "origin":
            phrase = f"{sub} originated from {objs[0]}"
        elif pred == "genre":
            phrase = f"{sub} performs {objs[0]} music"
        elif pred == "instrument":
            phrase = f"{sub} plays the {objs[0]}"
        elif pred == "nationality":
            phrase = f"{sub} is {objs[0]}"
        else:
            phrase = f"{sub} {pred.replace('_', ' ')} {join_objs(objs)}"
        other_sentences.append(phrase + ".")

    # Combine all sentences
    return " ".join([main_sentence] + other_sentences)

# EVOLVE-BLOCK-END

